// n8n Code node (JavaScript)
// Input: items seperti contoh payload TheHive trigger
// Output: 1 item per event dengan struktur ter-normalisasi

function toIso(v) {
  if (v == null) return null;
  if (typeof v === 'number') {
    const ms = v > 1e12 ? v : v * 1000; // dukung detik/milidetik
    const d = new Date(ms);
    return isNaN(d.getTime()) ? null : d.toISOString();
  }
  if (typeof v === 'string') {
    const d = new Date(v);
    return isNaN(d.getTime()) ? null : d.toISOString();
  }
  return null;
}

const sevLabelMap = { 1: 'LOW', 2: 'MEDIUM', 3: 'HIGH', 4: 'CRITICAL', 0: 'UNKNOWN' };
const tlpLabelMap = { 0: 'CLEAR', 1: 'GREEN', 2: 'AMBER', 3: 'RED' };

function computeSeverityLabel(num, lbl) {
  if (lbl && String(lbl).trim()) return String(lbl).toUpperCase();
  if (typeof num === 'number') return sevLabelMap[num] || 'UNKNOWN';
  return 'UNKNOWN';
}

// Heuristik "verified": sesuaikan jika kamu punya field khusus (mis. customFieldValues.verified)
function computeVerified(o = {}) {
  const tags = (o.tags || []).map(t => String(t).toLowerCase());
  const stage = String(o.stage || o.status || '').toLowerCase();
  const res = String(o.resolutionStatus || '').toLowerCase();
  const cfv = o.customFieldValues || {};
  const cfKeys = Object.keys(cfv).map(k => k.toLowerCase());

  if (['truepositive','confirmed','verified','resolved','closed']
      .some(k => stage.includes(k) || res.includes(k))) return true;

  if (tags.some(t => ['verified','truepositive','confirmed'].includes(t))) return true;

  // jika ada custom field yang mengindikasikan verified = true
  if (cfKeys.some(k => k.includes('verified'))) {
    try {
      const anyTrue = Object.values(cfv).some(v =>
        (typeof v === 'boolean' && v) ||
        (typeof v === 'string' && v.toLowerCase() === 'true')
      );
      if (anyTrue) return true;
    } catch (_) {}
  }
  return false;
}

// Ambil nilai dari tag dengan format "key=value"
function extractTagValue(tags = [], key) {
  const pref = `${key}=`;
  const hit = tags.find(t => String(t).startsWith(pref));
  return hit ? String(hit).slice(pref.length) : null;
}

// Ambil nilai dari customFieldValues (case-insensitive key match)
function getFromCFV(cfv = {}, key) {
  if (cfv == null) return null;
  if (Object.prototype.hasOwnProperty.call(cfv, key)) return cfv[key];
  const found = Object.keys(cfv).find(k => String(k).toLowerCase() === String(key).toLowerCase());
  return found ? cfv[found] : null;
}

return items.map(item => {
  const root = item.json || {};
  const event = root.event || root.body?.event || 'unknown';

  const body = root.body || root;                 // kompatibel kalau payload langsung di root
  const obj  = body.object || body.context || {}; // ambil Case object
  const org  = body.organisation || {};

  // Ambil severity (prioritaskan object.severity; fallback ke details.severity)
  const sevNum = (typeof obj.severity === 'number')
    ? obj.severity
    : (typeof body.details?.severity === 'number' ? body.details.severity : null);

  // --- EKSTRA: ambil agent_ip dari tags ---
  const tags = Array.isArray(obj.tags) ? obj.tags : [];
  const desc  = obj.customFieldValues.description || body.customFieldValues.description || {};

  const agentIp = extractTagValue(tags, 'agent_ip');

  // Agent sekarang ambil dari assignee (biarkan dalam bentuk email)
  const agentVal = obj.assignee || null;

  // Caller sekarang ambil dari friendlyName (top-level)
  const callerVal = root.friendlyName.toLowerCase()|| null;
  // ------------------------------------------------------------------------------

  const normalized = {
    source: 'thehive5',
    event,
    desc,
    organisation: {
      id: org.organisationId || null,
      name: org.organisation || null,
    },
    dedupKey: obj._id || body.objectId || body.rootId || null, // pakai di iTop & DB checkpoint
    case: {
      id: obj._id || null,
      number: obj.number ?? null,
      title: obj.title ?? null,
      description: obj.description ?? null, // markdown asli biar bisa dilog/attach
      status: obj.status ?? null,
      stage: obj.stage ?? null,
      assignee: obj.assignee ?? null,
      severity: sevNum,
      severityLabel: computeSeverityLabel(sevNum, obj.severityLabel),
      tlp: obj.tlp ?? null,
      tlpLabel: obj.tlpLabel || (obj.tlp != null ? tlpLabelMap[obj.tlp] : null),
      pap: obj.pap ?? null,
      tags,
      createdAt: toIso(obj._createdAt),
      updatedAt: toIso(obj._updatedAt),
      startDate: toIso(obj.startDate),
      alertDate: toIso(obj.alertDate),
      isVerified: computeVerified(obj),

      agent_ip: agentIp ?? null,
      agent: agentVal ?? null,   // dari assignee (email utuh)
      caller: callerVal ?? null, // dari friendlyName
    },
    change: body.details || {}, // apa yang berubah pada event update
    actor: body._createdBy || obj._updatedBy || null,
    timestamps: {
      eventCreatedAt: toIso(body._createdAt),
    },
    raw: {
      objectType: body.objectType || 'Case',
      objectId: body.objectId || null,
      requestId: body.requestId || null,
    },
  };

  return { json: normalized };
});

// Decide Path (pakai enriched JSON dari item saat ini)

function normBool(v) {
  return v === true || v === 'true' || v === 't' || v === 1 || v === '1';
}

function normHash(v) {
  if (v == null) return null;
  if (typeof v !== 'string') v = String(v);
  return v.trim().toLowerCase(); // handle trailing spaces & case
}

return items.map(item => {
  const j = item.json || {};

  const thehiveId = j.thehive_id || j.dedupKey || (j.case && j.case.id) || j['case.id'] || null;
  const oldHash   = normHash(j.thehive_hash || j.case_hash_old);
  const newHash   = normHash(j.case_hash || j.thehive_new_hash);

  // Ambil event dari beberapa kemungkinan field
  const ev = String(
    j.event ??
    j['case.event'] ??
    (j.case && j.case.event) ??
    ''
  ).toLowerCase();

  // already_sent bisa true, atau kita anggap sudah pernah terkirim kalau ada itop_ref
  const alreadySent = normBool(j.already_sent) || !!j.itop_ref;

  // PRIORITAS: jika event adalah case_delete, langsung ke mode 'delete'
  if (ev === 'case_delete') {
    return {
      json: {
        mode: 'delete',
        reason: 'case-deleted',
        thehive_id: thehiveId,
        case_hash: newHash,
        prev_hash: oldHash,
        itop_ref: j.itop_ref || null,

        // teruskan field lain (opsional)
        source: j.source,
        event: j.event || j['case.event'] || 'case_delete',
        organisation: j.organisation,
        change: j.change,
        actor: j.actor,
        timestamps: j.timestamps,
        raw: j.raw
      }
    };
  }

  // Default behavior: create / update / noop by hash
  let mode = 'create';
  let reason = 'not-in-db';

  if (alreadySent) {
    if (oldHash && newHash) {
      if (oldHash === newHash) {
        mode = 'noop';
        reason = 'same-hash';
      } else {
        mode = 'update';
        reason = 'hash-changed';
      }
    } else {
      mode = 'update';
      reason = 'already-sent-no-old-hash';
    }
  }

  return {
    json: {
      mode,
      reason,
      thehive_id: thehiveId,
      case_hash: newHash,
      prev_hash: oldHash,
      itop_ref: j.itop_ref || null,

      // (opsional) teruskan field penting lain ke downstream
      source: j.source,
      event: j.event || j['case.event'] || '',
      organisation: j.organisation,
      change: j.change,
      actor: j.actor,
      timestamps: j.timestamps,
      raw: j.raw
    }
  };
});

