// n8n Code node (JavaScript)
// Mod: remove rule.id, rule.level, agent.id columns; add Source IP (data.srcip)

function escapeRegExp(s) {
  return String(s).replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}
function htmlEscape(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;');
}
function coerceNum(v) {
  if (v == null) return null;
  const n = Number(String(v).trim());
  return Number.isFinite(n) ? n : null;
}
function parseTs(ts) {
  if (!ts) return Number.POSITIVE_INFINITY;
  let s = String(ts).trim().replace(/\s+WIB$/i, '');
  if (/^\d{4}-\d{2}-\d{2}\s+\d{2}:\d{2}:\d{2}$/.test(s)) {
    const d = new Date(s.replace(' ', 'T'));
    if (!isNaN(d.getTime())) return d.getTime();
    const dZ = new Date(s.replace(' ', 'T') + 'Z');
    if (!isNaN(dZ.getTime())) return dZ.getTime();
  }
  const d = new Date(s);
  return isNaN(d.getTime()) ? Number.POSITIVE_INFINITY : d.getTime();
}
function extractBlocks(text) {
  if (!text) return [];
  const t = String(text);
  const timeRe = /\|\s*\*\*timestamp\*\*\s*\|\s*([^\n|]+)\s*\|?/gi;
  const matches = [...t.matchAll(timeRe)];
  if (matches.length === 0) return [];
  const blocks = [];
  for (let i = 0; i < matches.length; i++) {
    const start = matches[i].index ?? 0;
    const end = (i < matches.length - 1) ? (matches[i + 1].index ?? t.length) : t.length;
    const seg = t.slice(start, end);
    const ts = matches[i][1].trim();
    blocks.push({ ts, seg });
  }
  return blocks;
}
function getVal(seg, key) {
  const re = new RegExp(`\\|\\s*\\*\\*${escapeRegExp(key)}\\*\\*\\s*\\|\\s*([^|\\n]+)`, 'i');
  const m = seg.match(re);
  return m ? m[1].trim() : null;
}

function buildHtmlTable(rows) {
  const thStyle = 'border:1px solid #666;padding:4px 6px;text-align:left;font-weight:600;';
  const tdStyle = 'border:1px solid #666;padding:4px 6px;text-align:left;';
