function appendDescAfterTable(tableHtml, desc) {
  const d = String(desc ?? '').trim();
  if (!d) return tableHtml;

  const boxStyle = 'margin-top:8px;padding:8px;border:1px dashed #999;border-radius:4px;background:#fff;font-size:12px;line-height:1.4;';
  const labelStyle = 'font-weight:600;margin-bottom:4px;';
  return `
    ${tableHtml}
    <div style="${boxStyle}">
      <div style="${labelStyle}">Summary:</div>
      <div>${htmlEscape(d)}</div>
    </div>
  `.trim();
}

function makeOneItemForGroup(groupRowsSortedAsc, ctx) {
  const earliest = groupRowsSortedAsc[0];
  const tableHtml = buildHtmlTable(groupRowsSortedAsc);
  const summaryHtml = appendDescAfterTable(tableHtml, ctx.desc);

  return {
    json: {
      event: ctx.eventType,
      'case.id': ctx.caseId,
      'case.title': ctx.caseTitle,
      'case.severity': ctx.caseSeverity,
      'case.severityLabel': ctx.caseSevLabel,
      'case.status': ctx.caseStatus,
      'case.stage': ctx.caseStage,
      'case.summary': ctx.caseSummary,
      timestamp: earliest.ts,
      tags: ctx.tags,
      caller: ctx.caller,
      agent: ctx.agent,
      desc: ctx.desc,

      // keep original top-level fields you want (optional)
      'rule.description': earliest['rule.description'],
      'agent.name': earliest['agent.name'],
      'agent.ip': earliest['agent.ip'],
      'data.srcip': earliest['data.srcip'] ?? null,

      summary: summaryHtml
    }
  };
}

return items.flatMap(item => {
  const root = item.json || {};
  const desc         = root.desc ?? root.case?.desc ?? '';
  const mdDesc       = root.case?.description || root.description || '';
  const caseSummary  = root.change?.summary ?? root['case.summary'] ?? null;
  const caseId       = root.case?.id ?? null;
  const caseSeverity = root.case?.severity ?? null;
  const caseStatus   = root.case?.status ?? null;
  const caseTitle    = root.case?.title ?? null;
  const caseSevLabel = (root.case?.severityLabel ?? root.case?.severitylabel ?? null) || null;
  const caseStage    = root.case?.stage ?? null;
  const eventType    = root.event ?? null;
  const tags         = root.case?.tags ?? null;
  const caller       = root.case?.caller ?? null;
  const agent        = root.case?.agent ?? null;

  const blocks = extractBlocks(mdDesc);

  // Group semua finding per signature (rule.id + agent.id)
  // NOTE: grouping tetap pakai rule.id + agent.id walau kolomnya dihapus dari tabel.
  const mapBySig = new Map();
  for (const b of blocks) {
    const ruleDesc  = getVal(b.seg, 'rule.description');
    const ruleId    = getVal(b.seg, 'rule.id');          // for grouping
    const agentId   = getVal(b.seg, 'agent.id');         // for grouping
    const agentName = getVal(b.seg, 'agent.name');
    const agentIp   = getVal(b.seg, 'agent.ip');

    // MOD: ambil srcip (coba key kecil & key besar)
    const srcip = getVal(b.seg, 'data.srcip') ?? getVal(b.seg, 'Data.srcip');

    if (!ruleId) continue;

    const row = {
      ts: b.ts,
      tsMs: parseTs(b.ts),
      'rule.description': ruleDesc,
      'agent.name': agentName,
      'agent.ip': agentIp,
      'data.srcip': srcip ?? '' // kalau gak ada, kosong
    };

    const sig = `${ruleId}::${agentId ?? ''}`;
    if (!mapBySig.has(sig)) mapBySig.set(sig, []);
    mapBySig.get(sig).push(row);
  }

  const ctx = {
    caseId, caseSeverity, caseStatus, caseTitle, caseSevLabel, caseStage,
    eventType, caseSummary, tags, caller, agent,
    desc
  };

  const results = [...mapBySig.values()]
    .map(rows => rows.sort((a, b) => a.tsMs - b.tsMs))
    .map(sortedRows => makeOneItemForGroup(sortedRows, ctx));

  return results;
});

