// --------- CrowdStrike ----------
function extractAttackTimes(desc) {
  const t = String(desc || '');
  const sectionRe = /###\s*Attack\s+Times[\s\S]*?(\|[^\n]*\n\|[^\n]*\n([\s\S]*?))(?:\n###|\n*$)/i;
  const m = t.match(sectionRe);
  if (!m) return [];
  const tableBody = m[2] || '';
  const rows = [];
  const lineRe = /^\|\s*([^\|]+?)\s*\|\s*$/gm;
  let lm;
  while ((lm = lineRe.exec(tableBody)) !== null) {
    const val = lm[1].trim();
    if (!val || /^-+$/.test(val)) continue;
    rows.push(val);
  }
  return rows;
}
function collectRowsCrowdStrike(desc) {
