  const times = attackTimes.length ? attackTimes : (ctxTs ? [ctxTs] : []);
  const rows = times.map(ts => ({
    ts,
    tsMs: parseTs(ts),
    detection_name: displayName,
    ioc_type: iocType,
    ioc_value: iocValue,
    hostname,
    user_name: userName,
    local_ip: localIp
