      'proc.name': proc || null,
      'proc.pid': procPid,
      'log.level': lvl || null,
      message: msg || null,
      sig: `${file}|${proc}|${lvl}|${normalizeMsg(msg)}`,
      pretty: `[${file}] ${proc}${pid ? '['+pid+']' : ''}${lvl ? ' · ' + lvl : ''} — ${msg}`
    };
  }

  // Fallback: LEVEL: message
  const re2 = /^(ERROR|WARN(?:ING)?|INFO|DEBUG)\s*:?\s*(.*)$/i;
