  const miti   = firstNonEmpty(kv['threatInfo.mitigationStatusDescription'], kv['threatInfo.mitigationStatus']);
  const inci   = firstNonEmpty(kv['threatInfo.incidentStatusDescription'], kv['threatInfo.incidentStatus']);

  const sigPrimary = firstNonEmpty(tId, sha256, tName, '');
  const sigAgent   = firstNonEmpty(agentId, agentNm, agentIp, '');
  const sig = `${sigPrimary}::${sigAgent}`;

  return {
    sig,
    tsRaw: tsChoice,
    ts: fmtTs(tsChoice),
    tsMs: parseTs(tsChoice),
    'agent.id': firstNonEmpty(coerceNum(agentId), agentId),
    'agent.name': firstNonEmpty(agentNm),
    'agent.ip': firstNonEmpty(agentIp),
    'threat.id': firstNonEmpty(coerceNum(tId), tId),
    'threat.name': firstNonEmpty(tName),
    'threat.classification': firstNonEmpty(cls),
    'threat.confidence': firstNonEmpty(conf),
    'threat.sha256': firstNonEmpty(sha256),
    'threat.filePath': firstNonEmpty(fpath),
    'threat.mitigationStatus': firstNonEmpty(miti),
    'threat.incidentStatus': firstNonEmpty(inci),
  };
}

function buildHtmlTable(rows) {
  const th = 'border:1px solid #666;padding:4px 6px;text-align:left;font-weight:600;';
  const td = 'border:1px solid #666;padding:4px 6px;text-align:left;';
  const caption = '<div style="font-size:14px;font-weight:600;margin:6px 0 4px;">SentinelOne Findings</div>';
  const header = `
    <tr>
      <th style="${th}">#</th>
      <th style="${th}">Timestamp</th>
      <th style="${th}">Host</th>
      <th style="${th}">Agent IP</th>
      <th style="${th}">Threat Name</th>
      <th style="${th}">Classification</th>
      <th style="${th}">Confidence</th>
      <th style="${th}">SHA256</th>
      <th style="${th}">File Path</th>
      <th style="${th}">Mitigation</th>
      <th style="${th}">Incident</th>
    </tr>`;
  const body = rows.map((r, i) => {
    const shaShort = r['threat.sha256'] ? `${String(r['threat.sha256']).slice(0,12)}…` : '';
    return `
      <tr>
        <td style="${td}">${i + 1}</td>
        <td style="${td}">${htmlEscape(r.ts)}</td>
        <td style="${td}">${htmlEscape(r['agent.name'] ?? '')}</td>
        <td style="${td}">${htmlEscape(r['agent.ip'] ?? '')}</td>
        <td style="${td}">${htmlEscape(r['threat.name'] ?? '')}</td>
        <td style="${td}">${htmlEscape(r['threat.classification'] ?? '')}</td>
        <td style="${td}">${htmlEscape(r['threat.confidence'] ?? '')}</td>
        <td style="${td}" title="${htmlEscape(r['threat.sha256'] ?? '')}">${htmlEscape(shaShort)}</td>
        <td style="${td}">${htmlEscape(r['threat.filePath'] ?? '')}</td>
        <td style="${td}">${htmlEscape(r['threat.mitigationStatus'] ?? '')}</td>
        <td style="${td}">${htmlEscape(r['threat.incidentStatus'] ?? '')}</td>
      </tr>`;
  }).join('');

  return `
    <div style="border:1px solid #7fb3d5;background:#ecf5fb;border-radius:4px;padding:8px;font-family:system-ui,Segoe UI,Arial,sans-serif;">
      ${caption}
      <table style="border-collapse:collapse;width:100%;table-layout:fixed;font-size:12px;">
        ${header}
        ${body}
      </table>
    </div>`.trim();
}

function makeOneItemForGroup(groupRowsAsc, ctx) {
  const earliest = groupRowsAsc[0];
  const tableHtml = buildHtmlTable(groupRowsAsc);
  return {
    json: {
      event: ctx.eventType,
      'case.id': ctx.caseId,
      'case.title': ctx.caseTitle,
      'case.severity': ctx.caseSeverity,
      'case.severityLabel': ctx.caseSevLabel,
      'case.status': ctx.caseStatus,
      'case.stage': ctx.caseStage,
      'case.summary': ctx.caseSummary, // tidak diubah
      timestamp: earliest.ts,
      tags: ctx.tags,
      agent: ctx.agent,
      caller: ctx.caller,
      // utama dari earliest
      'agent.id': earliest['agent.id'],
      'agent.name': earliest['agent.name'],
      'agent.ip': earliest['agent.ip'],
      'threat.id': earliest['threat.id'],
      'threat.name': earliest['threat.name'],
      'threat.classification': earliest['threat.classification'],
      'threat.confidence': earliest['threat.confidence'],
      'threat.sha256': earliest['threat.sha256'],
      'threat.filePath': earliest['threat.filePath'],
      'threat.mitigationStatus': earliest['threat.mitigationStatus'],
      'threat.incidentStatus': earliest['threat.incidentStatus'],
      // tabel HTML semua finding
      summary: tableHtml
    }
  };
}

// ---------- main ----------
return items.flatMap(item => {
  const root = item.json || {};
  const obj = root.body?.object || root.object || root.case || {};
  const desc = obj.description || root.description || '';

  const caseSummary = firstDefined(obj.summary, root.change?.summary, root['case.summary']);
  const ctx = {
    eventType: firstDefined(root.event, root.body?.action),
    caseId: firstDefined(obj._id, obj.id),
    caseTitle: obj.title ?? null,
    caseSeverity: obj.severity ?? null,
    caseSevLabel: obj.severityLabel ?? null,
    caseStatus: obj.status ?? null,
    caseStage: obj.stage ?? null,
    caseSummary,
    agent: obj.agent ?? null,
    caller: obj.caller ?? null,
    tags: obj.tags ?? null,

  };

  const kv = extractKVFromMarkdown(desc);
  const rowsRaw = [];
  if (Object.keys(kv).length > 0) {
    rowsRaw.push(buildRowFromKV(kv, root));
  } else {
    // fallback minimal
    const ts = firstDefined(obj.alertDate, obj._updatedAt, obj._createdAt);
    rowsRaw.push({
      sig: `${firstNonEmpty(obj.title, '')}::${firstNonEmpty(obj.number, '')}`,
      tsRaw: ts, ts: fmtTs(ts), tsMs: parseTs(ts),
      'agent.id': null, 'agent.name': null, 'agent.ip': null,
      'threat.id': null, 'threat.name': firstNonEmpty(obj.title),
      'threat.classification': null, 'threat.confidence': null,
      'threat.sha256': null, 'threat.filePath': null,
      'threat.mitigationStatus': null, 'threat.incidentStatus': null,
    });
  }

  const bySig = new Map();
  for (const r of rowsRaw) {
    if (!bySig.has(r.sig)) bySig.set(r.sig, []);
    bySig.get(r.sig).push(r);
  }

  const out = [];
  for (const rows of bySig.values()) {
    rows.sort((a, b) => a.tsMs - b.tsMs);
    out.push(makeOneItemForGroup(rows, ctx));
  }
  return out;
});

