const allowed = new Set(['Incident', 'UserRequest']);
const seen = new Set();          // buat dedupe kalau ada duplikasi
const out = [];

// helper: HTML -> text sederhana
function htmlToText(html = '') {
  return String(html)
    .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
    .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/\r?\n\s*\r?\n/g, '\n')
    .trim();
}

for (const it of items) {
  const objs = it.json?.objects || {};
  for (const [key, obj] of Object.entries(objs)) {
    const cls = obj.class || (key.includes('::') ? key.split('::')[0] : 'Unknown');
    if (!allowed.has(cls)) continue;

    const f = obj.fields || {};
    const id = String(f.id ?? obj.key ?? (key.split('::')[1] || ''));
    const composite_id = `${cls}:${id}`;
    if (seen.has(composite_id)) continue;  // dedupe antar items
    seen.add(composite_id);

    const html = f.description || '';
    const text = htmlToText(html);

    out.push({
      json: {
        // identitas untuk mapping & checkpoint
        itop_class: cls,                 // "Incident" / "UserRequest"
        itop_id: id,                     // e.g. "6"
        itop_ref: f.ref || '',           // e.g. "I-000006" / "R-000004"
        composite_id,                    // e.g. "Incident:6"

